import { invokeFunction } from '../../../utils/zcutils';
import { getRaceScrollView } from './continuousRace-handler';

export async function onRedrawHandler(chart) {
    var race = chart.racing,
        frameInfo = race.keyFrameInfo,
        scroll = chart.scroll,
        instance = scroll && scroll.brushInstance,
        continuousRaceInfo = race.continuousRaceInfo;
    frameInfo.index = -1;
    // continuousRaceInfo = {};
    continuousRaceInfo.index = -1;
    continuousRaceInfo.initialValue = null;
    continuousRaceInfo.dataPositionMap = {};
    continuousRaceInfo.positionArr = null;
    continuousRaceInfo.timeCategoriesPosition = [];
    if(!race.keyFramedRace){
        // chart.racing.raceScale = null;
    }
    if (race.started) {
        await new Promise(function(resolve, reject) {
            var _i = setInterval(function() {
                if (race.allowRedraw) {
                    clearInterval(_i);
                    resolve();
                }
            }, 10);
        });
    }
    if (chart.scroll) {
        chart.cache.scroll.domain = null;
        chart.scroll.lastScroll = null;
        race.scrollView = getRaceScrollView(chart, !!chart.scroll.brushScale.bandwidth, null, true);
    }
    race.syncTransition = chart.container.transition().duration(0);
    chart.racing.interrupt = true;
    if (race.started) {
        invokeFunction(race.events.onInterrupt, race, chart);
    }
}
